10	SQL Backup	{"type": "doc", "content": [{"type": "codeBlock", "attrs": {"language": null}, "content": [{"text": "WITH REPCARD_RAW AS (\\n\\tSELECT\\n\\t    u_mpc_report_card.season,\\n\\t    u_mpc_report_card.id,\\n\\t    u_mpc_report_card.studentsdcid,\\n\\t    u_mpc_report_card.shapes,\\n\\t    u_mpc_report_card.shapes_na,\\n\\t    u_mpc_report_card.colors,\\n\\t    u_mpc_report_card.colors_na,\\n\\t    u_mpc_report_card.rote_counting,\\n\\t    u_mpc_report_card.rote_counting_na,\\n\\t    u_mpc_report_card.numbers,\\n\\t    u_mpc_report_card.numbers_na,\\n\\t    u_mpc_report_card.one_to_one_corresp,\\n\\t    u_mpc_report_card.one_to_one_corresp_na,\\n\\t    u_mpc_report_card.upper,\\n\\t    u_mpc_report_card.upper_na,\\n\\t    u_mpc_report_card.lower,\\n\\t    u_mpc_report_card.lower_na,\\n\\t    u_mpc_report_card.letter_sound,\\n\\t    u_mpc_report_card.letter_sound_na,\\n\\t    REPLACE(REPLACE(REPLACE(u_mpc_report_card.cognitive_comment, '\\"', '\\\\\\"'), CHR(13), ''), CHR(10), '\\\\n') as cognitive_comment,\\n\\t    u_mpc_report_card.what_q,\\n\\t    u_mpc_report_card.what_q_na,\\n\\t    u_mpc_report_card.where_q,\\n\\t    u_mpc_report_card.where_q_na,\\n\\t    u_mpc_report_card.when_q,\\n\\t    u_mpc_report_card.when_q_na,\\n\\t    u_mpc_report_card.why_q,\\n\\t    u_mpc_report_card.why_q_na,\\n\\t    u_mpc_report_card.who_q,\\n\\t    u_mpc_report_card.who_q_na,\\n\\t    u_mpc_report_card.states_name,\\n\\t    u_mpc_report_card.states_name_na,\\n\\t    CASE WHEN u_mpc_report_card.states_age = '1' THEN 'Yes' WHEN u_mpc_report_card.states_age = '0' THEN 'No' END states_age,\\n\\t    u_mpc_report_card.states_age_na,\\n\\t    CASE WHEN u_mpc_report_card.identifies_name = '1' THEN 'Yes' WHEN u_mpc_report_card.identifies_name = '0' THEN 'No' END identifies_name,\\n\\t    u_mpc_report_card.identifies_name_na,\\n\\t    REPLACE(REPLACE(REPLACE(u_mpc_report_card.language_comment, '\\"', '\\\\\\"'), CHR(13), ''), CHR(10), '\\\\n') as language_comment,\\n\\t    CASE WHEN u_mpc_report_card.pencil_hold = '1' THEN 'Yes' WHEN u_mpc_report_card.pencil_hold = '0' THEN 'No' END pencil_hold,\\n\\t    u_mpc_report_card.pencil_hold_na,\\n\\t    CASE WHEN u_mpc_report_card.cut_line = '1' THEN 'Yes' WHEN u_mpc_report_card.cut_line = '0' THEN 'No' END cut_line,\\n\\t    u_mpc_report_card.cut_line_na,\\n\\t    u_mpc_report_card.writes_name,\\n\\t    u_mpc_report_card.writes_name_na,\\n\\t    REPLACE(REPLACE(REPLACE(u_mpc_report_card.motor_comment, '\\"', '\\\\\\"'), CHR(13), ''), CHR(10), '\\\\n') as motor_comment,\\n\\t    CASE WHEN u_mpc_report_card.takes_turns = '1' THEN 'Yes' WHEN u_mpc_report_card.takes_turns = '0' THEN 'No' END takes_turns,\\n\\t    u_mpc_report_card.takes_turns_na,\\n\\t    u_mpc_report_card.play_part,\\n\\t    u_mpc_report_card.play_part_na,\\n\\t    u_mpc_report_card.follows_direction,\\n\\t    u_mpc_report_card.follows_direction_na,\\n\\t    REPLACE(REPLACE(REPLACE(u_mpc_report_card.social_comment, '\\"', '\\\\\\"'), CHR(13), ''), CHR(10), '\\\\n') as social_comment,\\n\\t    CASE WHEN u_mpc_report_card.remove_coat = '1' THEN 'Yes' WHEN u_mpc_report_card.remove_coat = '0' THEN 'No' END remove_coat,\\n\\t    u_mpc_report_card.remove_coat_na,\\n\\t    CASE WHEN u_mpc_report_card.puts_coat = '1' THEN 'Yes' WHEN u_mpc_report_card.puts_coat = '0' THEN 'No' END puts_coat,\\n\\t    u_mpc_report_card.puts_coat_na,\\n\\t    CASE WHEN u_mpc_report_card.unzip_coat = '1' THEN 'Yes' WHEN u_mpc_report_card.unzip_coat = '0' THEN 'No' END unzip_coat,\\n\\t    u_mpc_report_card.unzip_coat_na,\\n\\t    CASE WHEN u_mpc_report_card.zip_coat = '1' THEN 'Yes' WHEN u_mpc_report_card.zip_coat = '0' THEN 'No' END zip_coat,\\n\\t    u_mpc_report_card.zip_coat_na,\\n\\t    CASE WHEN u_mpc_report_card.ind_bathroom = '1' THEN 'Yes' WHEN u_mpc_report_card.ind_bathroom = '0' THEN 'No' END ind_bathroom,\\n\\t    u_mpc_report_card.ind_bathroom_na,\\n\\t    CASE WHEN u_mpc_report_card.clean_up = '1' THEN 'Yes' WHEN u_mpc_report_card.clean_up = '0' THEN 'No' END clean_up,\\n\\t    u_mpc_report_card.clean_up_na,\\n\\t    REPLACE(REPLACE(REPLACE(u_mpc_report_card.help_comment, '\\"', '\\\\\\"'), CHR(13), ''), CHR(10), '\\\\n') as help_comment,\\n\\t    u_mpc_report_card.whenmodified,\\n\\t    ROW_NUMBER() OVER (\\n            PARTITION BY u_mpc_report_card.studentsdcid, u_mpc_report_card.season \\n            ORDER BY u_mpc_report_card.whenmodified DESC\\n        ) as rn\\n\\tFROM\\n\\t    u_mpc_report_card\\n\\tWHERE\\n\\t\\t-- change to curyearid minus 1 later.\\n\\t\\t-- u_mpc_report_card.yearid = ~(curyearid) - 1\\n\\t    u_mpc_report_card.yearid = ~(curyearid)\\n\\t    AND u_mpc_report_card.season in ('Fall', 'Winter', 'Spring')\\n\\tORDER BY decode(u_mpc_report_card.season,'Fall',1,'Winter',2,'Spring',3,4)\\n),\\nREPCARD AS (\\n    SELECT * FROM REPCARD_RAW WHERE rn = 1\\n),\\nKQUEST AS (\\n\\tselect\\n\\t\\tu_kinder_questionnaire.studentsdcid,\\n\\t\\tcase when to_char(u_kinder_questionnaire.is_new_student) is null then 'N'\\n\\t\\t     when to_char(u_kinder_questionnaire.is_new_student) = '0' then 'N'\\n\\t\\t\\t when to_char(u_kinder_questionnaire.is_new_student) = '1' then 'Y'\\n\\t\\t\\t else to_char(u_kinder_questionnaire.is_new_student) end as isNewStudent,\\n\\t\\tu_kinder_questionnaire.which_hand as which_hand,\\n\\t\\tcase when to_char(u_kinder_questionnaire.is_new_student) is null then 'Yes, Minooka Primary Center'\\n\\t\\t\\t when to_char(u_kinder_questionnaire.is_new_student) = '1' and u_custom_demographic.previous_school_attended = 'No' then 'No'\\n\\t\\t\\t when to_char(u_kinder_questionnaire.is_new_student) = '0' and u_custom_demographic.previous_school_attended = 'No' then 'No'\\n\\t\\t\\t else u_custom_demographic.previous_school_attended || ', ' || u_custom_demographic.previous_school_name end as previousSchool,\\n\\t\\tcase when u_kinder_questionnaire.prev_daycare  = 'Yes' then 'Yes, ' || u_kinder_questionnaire.prev_daycare_name\\n\\t\\t\\t else u_kinder_questionnaire.prev_daycare end as prevDaycare,\\n\\t\\tu_kinder_questionnaire.prev_babysitter as prevBabysitter,\\n\\t\\tu_kinder_questionnaire.medical_comments as medicalComments,\\n\\t\\tu_kinder_questionnaire.iep as IEP,\\n\\t\\tu_kinder_questionnaire.plan_504 as plan504,\\n\\t\\tu_kinder_questionnaire.ei as ei,\\n\\t\\tu_kinder_questionnaire.outside_ot as outsideOT,\\n\\t\\tu_kinder_questionnaire.outside_pt as outsidePT,\\n\\t\\tu_kinder_questionnaire.outside_speech as oustideSpeech,\\n\\t\\tcase when u_kinder_questionnaire.outside_other = 'Yes' then u_kinder_questionnaire.outside_other || ', ' || u_kinder_questionnaire.outside_other_name\\n\\t\\t\\t else u_kinder_questionnaire.outside_other end as outsideOther,\\n\\t\\tu_kinder_questionnaire.strengths_interests as strengths,\\n\\t\\tu_kinder_questionnaire.play_well as playWell,\\n\\t\\tu_kinder_questionnaire.share_take_turns as shareTakeTurns,\\n\\t\\tu_kinder_questionnaire.recognize_own_name as recongizeOwnName,\\n\\t\\tu_kinder_questionnaire.print_name as printName,\\n\\t\\tu_kinder_questionnaire.recognize_alphabet as recongizeAlphabet,\\n\\t\\tu_kinder_questionnaire.print_alphabet as printAlphabet,\\n\\t\\tu_kinder_questionnaire.look_read_books as lookReadBooks,\\n\\t\\tu_kinder_questionnaire.know_colors as knowColors,\\n\\t\\tu_kinder_questionnaire.can_count_objects_to_5 as canCount,\\n\\t\\tu_kinder_questionnaire.use_writing_utensils as useWritingUtensils,\\n\\t\\tu_kinder_questionnaire.use_scissors as useScissors,\\n\\t\\tu_kinder_questionnaire.seperate_from_parents_easily as seperateFromParents,\\n\\t\\tu_kinder_questionnaire.organized_sports as organizedSports,\\n\\t\\tu_kinder_questionnaire.organized_music as organizedMusic,\\n\\t\\tu_kinder_questionnaire.organized_library as organizedLibrary,\\n\\t\\tcase when u_kinder_questionnaire.organized_other = 'Yes' then u_kinder_questionnaire.organized_other || ', ' || u_kinder_questionnaire.organized_other_details\\n\\t\\t\\t else u_kinder_questionnaire.organized_other end as organizedOther,\\n\\t\\tu_kinder_questionnaire.other_comments as otherComments\\n\\t\\n\\tfrom\\n\\t\\tu_kinder_questionnaire\\n\\t\\tLEFT JOIN u_custom_demographic ON u_kinder_questionnaire.studentsdcid = u_custom_demographic.studentsdcid\\n),\\nKSNAPSHOT As (\\n\\tSELECT\\n\\t\\tu_k_snapshot.studentsdcid,\\n\\t\\tu_k_snapshot.avoids,\\n\\t\\tu_k_snapshot.handed,\\n\\t\\tu_k_snapshot.sel,\\n\\t\\tu_k_snapshot.selnote,\\n\\t\\tu_k_snapshot.separate_from as separate,\\n\\t\\tu_k_snapshot.resp_name,\\n\\t\\tu_k_snapshot.snack,\\n\\t\\tu_k_snapshot.transition,\\n\\t\\tu_k_snapshot.identifies_name,\\n\\t\\tu_k_snapshot.ind_bathroom,\\n\\t\\tu_k_snapshot.participates,\\n\\t\\tu_k_snapshot.takes_turns,\\n\\t\\tu_k_snapshot.writes_name,\\n\\t\\tu_k_snapshot.pairs,\\n\\t\\tu_k_snapshot.pairwith\\n\\t\\t\\n\\tfrom\\n\\t\\tu_k_snapshot\\n)\\n\\nSELECT \\n\\tstudents.id,\\n    students.lastfirst,\\n    students.student_number,\\n    \\n    KQUEST.isNewStudent,\\n    KQUEST.previousSchool,\\n    KQUEST.prevDaycare,\\n    \\n    -- Cognitive Readiness\\n    \\n    \\tCASE WHEN REPCARDFALL.shapes IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.shapes IS NOT NULL THEN REPCARDFALL.shapes END ||\\n\\t    \\tCASE WHEN REPCARDFALL.shapes_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n    \\tCASE WHEN REPCARDWINTER.shapes IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.shapes IS NOT NULL THEN REPCARDWINTER.shapes END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.shapes_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n    \\tCASE WHEN REPCARDSPRING.shapes IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.shapes IS NOT NULL THEN REPCARDSPRING.shapes END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.shapes_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END\\n    AS \\"Shapes (9)\\",\\n\\t    CASE WHEN REPCARDFALL.colors IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.colors IS NOT NULL THEN REPCARDFALL.colors END ||\\n\\t    \\tCASE WHEN REPCARDFALL.colors_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.colors IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.colors IS NOT NULL THEN REPCARDWINTER.colors END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.colors_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.colors IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.colors IS NOT NULL THEN REPCARDSPRING.colors END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.colors_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN KQUEST.knowColors IS NOT NULL THEN 'Parent - Name 8 main colors?: ' || KQUEST.knowColors ||\\tchr(10) END\\n    AS \\"Colors (11)\\",\\n\\t    CASE WHEN REPCARDFALL.rote_counting IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.rote_counting IS NOT NULL THEN REPCARDFALL.rote_counting END ||\\n\\t    \\tCASE WHEN REPCARDFALL.rote_counting_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.rote_counting IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.rote_counting IS NOT NULL THEN REPCARDWINTER.rote_counting END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.rote_counting_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.rote_counting IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.rote_counting IS NOT NULL THEN REPCARDSPRING.rote_counting END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.rote_counting_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN KQUEST.canCount IS NOT NULL THEN 'Parent - Count objects to 5?: ' || KQUEST.canCount ||\\tchr(10) END\\n    AS \\"Rote Counting (100)\\",\\n\\t    CASE WHEN REPCARDFALL.numbers IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.numbers IS NOT NULL THEN REPCARDFALL.numbers END ||\\n\\t    \\tCASE WHEN REPCARDFALL.numbers_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.numbers IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.numbers IS NOT NULL THEN REPCARDWINTER.numbers END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.numbers_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.numbers IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.numbers IS NOT NULL THEN REPCARDSPRING.numbers END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.numbers_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END\\n    AS \\"Numbers (11)\\",\\n\\t    CASE WHEN REPCARDFALL.one_to_one_corresp IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.one_to_one_corresp IS NOT NULL THEN REPCARDFALL.one_to_one_corresp END ||\\n\\t    \\tCASE WHEN REPCARDFALL.one_to_one_corresp_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.one_to_one_corresp IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.one_to_one_corresp IS NOT NULL THEN REPCARDWINTER.one_to_one_corresp END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.one_to_one_corresp_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.one_to_one_corresp IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.one_to_one_corresp IS NOT NULL THEN REPCARDSPRING.one_to_one_corresp END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.one_to_one_corresp_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END\\n    AS \\"One-to-One Correspondence (11)\\",\\n\\t    CASE WHEN REPCARDFALL.upper IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.upper IS NOT NULL THEN REPCARDFALL.upper END ||\\n\\t    \\tCASE WHEN REPCARDFALL.upper_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.upper IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.upper IS NOT NULL THEN REPCARDWINTER.upper END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.upper_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.upper IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.upper IS NOT NULL THEN REPCARDSPRING.upper END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.upper_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN KQUEST.recongizeAlphabet IS NOT NULL THEN 'Parent - Recognize letters of the alphabet?: ' || KQUEST.recongizeAlphabet ||\\tchr(10) END\\n    AS \\"Upper (26)\\",\\n\\t    CASE WHEN REPCARDFALL.lower IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.lower IS NOT NULL THEN REPCARDFALL.lower END ||\\n\\t    \\tCASE WHEN REPCARDFALL.lower_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.lower IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.lower IS NOT NULL THEN REPCARDWINTER.lower END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.lower_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.lower IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.lower IS NOT NULL THEN REPCARDSPRING.lower END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.lower_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN KQUEST.recongizeAlphabet IS NOT NULL THEN 'Parent - Recognize letters of the alphabet?: ' || KQUEST.recongizeAlphabet ||\\tchr(10) END\\n    AS \\"Lower (26)\\",\\n\\t    CASE WHEN REPCARDFALL.letter_sound IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.letter_sound IS NOT NULL THEN REPCARDFALL.letter_sound END ||\\n\\t    \\tCASE WHEN REPCARDFALL.letter_sound_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.letter_sound IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.letter_sound IS NOT NULL THEN REPCARDWINTER.letter_sound END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.letter_sound_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.letter_sound IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.letter_sound IS NOT NULL THEN REPCARDSPRING.letter_sound END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.letter_sound_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END\\n    AS \\"Letter Sound (26)\\",\\n\\t\\tCASE WHEN KQUEST.lookReadBooks IS NOT NULL THEN 'Parent: ' || KQUEST.lookReadBooks ||\\tchr(10) END\\n    AS \\"Look at Books / Pretend to Read\\",\\n    \\tCASE WHEN REPCARDFALL.cognitive_comment IS NOT NULL THEN 'RC Fall: ' || REPCARDFALL.cognitive_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDWINTER.cognitive_comment IS NOT NULL THEN 'RC Winter: ' || REPCARDWINTER.cognitive_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDSPRING.cognitive_comment IS NOT NULL THEN 'RC Spring: ' || REPCARDSPRING.cognitive_comment || chr(10) END\\n    AS \\"Cognitive Comment\\",\\n    \\n    -- Language\\n    \\n\\t    CASE WHEN REPCARDFALL.what_q IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.what_q IS NOT NULL THEN REPCARDFALL.what_q END ||\\n\\t    \\tCASE WHEN REPCARDFALL.what_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.what_q IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.what_q IS NOT NULL THEN REPCARDWINTER.what_q END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.what_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.what_q IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.what_q IS NOT NULL THEN REPCARDSPRING.what_q END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.what_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"What Q (2)\\",\\n\\t    CASE WHEN REPCARDFALL.where_q IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.where_q IS NOT NULL THEN REPCARDFALL.where_q END ||\\n\\t    \\tCASE WHEN REPCARDFALL.where_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.where_q IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.where_q IS NOT NULL THEN REPCARDWINTER.where_q END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.where_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.where_q IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.where_q IS NOT NULL THEN REPCARDSPRING.where_q END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.where_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Where Q (2)\\",\\n\\t    CASE WHEN REPCARDFALL.when_q IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.when_q IS NOT NULL THEN REPCARDFALL.when_q END ||\\n\\t    \\tCASE WHEN REPCARDFALL.when_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.when_q IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.when_q IS NOT NULL THEN REPCARDWINTER.when_q END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.when_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.when_q IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.when_q IS NOT NULL THEN REPCARDSPRING.when_q END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.when_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"When Q (2)\\",\\n\\t    CASE WHEN REPCARDFALL.why_q IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.why_q IS NOT NULL THEN REPCARDFALL.why_q END ||\\n\\t    \\tCASE WHEN REPCARDFALL.why_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.why_q IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.why_q IS NOT NULL THEN REPCARDWINTER.why_q END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.why_q_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING