  \\tchr(10)\\n\\t    END \\n    AS \\"States Name\\",\\n\\t    CASE WHEN REPCARDFALL.states_age IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.states_age IS NOT NULL THEN REPCARDFALL.states_age END ||\\n\\t    \\tCASE WHEN REPCARDFALL.states_age_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.states_age IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.states_age IS NOT NULL THEN REPCARDWINTER.states_age END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.states_age_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.states_age IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.states_age IS NOT NULL THEN REPCARDSPRING.states_age END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.states_age_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"States Age\\",\\n\\t    CASE WHEN REPCARDFALL.identifies_name IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.identifies_name IS NOT NULL THEN REPCARDFALL.identifies_name END ||\\n\\t    \\tCASE WHEN REPCARDFALL.identifies_name_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.identifies_name IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.identifies_name IS NOT NULL THEN REPCARDWINTER.identifies_name END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.identifies_name_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.identifies_name IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.identifies_name IS NOT NULL THEN REPCARDSPRING.identifies_name END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.identifies_name_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN KSNAPSHOT.identifies_name IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.identifies_name || chr(10) END ||\\n\\t    CASE WHEN KQUEST.recongizeOwnName IS NOT NULL THEN 'Parent: ' || KQUEST.recongizeOwnName ||\\tchr(10) END\\n    AS \\"Identifies Name\\",\\n    \\tCASE WHEN REPCARDFALL.language_comment IS NOT NULL THEN 'RC Fall: ' || REPCARDFALL.language_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDWINTER.language_comment IS NOT NULL THEN 'RC Winter: ' || REPCARDWINTER.language_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDSPRING.language_comment IS NOT NULL THEN 'RC Spring: ' || REPCARDSPRING.language_comment || chr(10) END\\n    AS \\"Language Comment\\",\\n    \\n    -- Fine Motor\\n    \\n    \\tCASE WHEN KSNAPSHOT.handed IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.handed || chr(10) END ||\\n\\t    CASE WHEN KQUEST.which_hand IS NOT NULL THEN 'Parent: ' || KQUEST.which_hand ||\\tchr(10) END\\n\\tAS \\"Handedness\\",\\n\\t\\tCASE WHEN KQUEST.useWritingUtensils IS NOT NULL THEN 'Parent: ' || KQUEST.useWritingUtensils ||\\tchr(10) END\\n    AS \\"Use Writing Utensils\\",\\n\\t\\tCASE WHEN KQUEST.printAlphabet IS NOT NULL THEN 'Parent: ' || KQUEST.printAlphabet ||\\tchr(10) END\\n    AS \\"Print Alphabet\\",\\n\\t\\tCASE WHEN KQUEST.useScissors IS NOT NULL THEN 'Parent: ' || KQUEST.useScissors ||\\tchr(10) END\\n    AS \\"Use Scissors\\",\\n\\t    CASE WHEN REPCARDFALL.pencil_hold IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.pencil_hold IS NOT NULL THEN REPCARDFALL.pencil_hold END ||\\n\\t    \\tCASE WHEN REPCARDFALL.pencil_hold_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.pencil_hold IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.pencil_hold IS NOT NULL THEN REPCARDWINTER.pencil_hold END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.pencil_hold_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.pencil_hold IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.pencil_hold IS NOT NULL THEN REPCARDSPRING.pencil_hold END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.pencil_hold_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Pencil Hold\\",\\n\\t    CASE WHEN REPCARDFALL.cut_line IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.cut_line IS NOT NULL THEN REPCARDFALL.cut_line END ||\\n\\t    \\tCASE WHEN REPCARDFALL.cut_line_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.cut_line IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.cut_line IS NOT NULL THEN REPCARDWINTER.cut_line END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.cut_line_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.cut_line IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.cut_line IS NOT NULL THEN REPCARDSPRING.cut_line END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.cut_line_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Cuts on a Line\\",\\n\\t    CASE WHEN REPCARDFALL.writes_name IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.writes_name IS NOT NULL THEN REPCARDFALL.writes_name END ||\\n\\t    \\tCASE WHEN REPCARDFALL.writes_name_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.writes_name IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.writes_name IS NOT NULL THEN REPCARDWINTER.writes_name END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.writes_name_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.writes_name IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.writes_name IS NOT NULL THEN REPCARDSPRING.writes_name END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.writes_name_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN KSNAPSHOT.writes_name IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.writes_name || chr(10) END ||\\n\\t    CASE WHEN KQUEST.printName IS NOT NULL THEN 'Parent: ' || KQUEST.printName ||\\tchr(10) END\\n    AS \\"Writes Name\\",\\n    \\tCASE WHEN REPCARDFALL.motor_comment IS NOT NULL THEN 'RC Fall: ' || REPCARDFALL.motor_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDWINTER.motor_comment IS NOT NULL THEN 'RC Winter: ' || REPCARDWINTER.motor_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDSPRING.motor_comment IS NOT NULL THEN 'RC Spring: ' || REPCARDSPRING.motor_comment || chr(10) END\\n    AS \\"Fine Motor Comment\\",\\n    \\n    -- Social Skills\\n    \\n    \\tCASE WHEN KSNAPSHOT.separate IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.separate || chr(10) END ||\\n\\t    CASE WHEN KQUEST.seperateFromParents IS NOT NULL THEN 'Parent: ' || KQUEST.seperateFromParents || chr(10) END\\n\\tAS \\"Separates from Parents\\",\\n    \\n\\t    CASE WHEN REPCARDFALL.takes_turns IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.takes_turns IS NOT NULL THEN REPCARDFALL.takes_turns END ||\\n\\t    \\tCASE WHEN REPCARDFALL.takes_turns_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.takes_turns IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.takes_turns IS NOT NULL THEN REPCARDWINTER.takes_turns END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.takes_turns_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.takes_turns IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.takes_turns IS NOT NULL THEN REPCARDSPRING.takes_turns END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.takes_turns_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END  ||\\n\\t    CASE WHEN KSNAPSHOT.takes_turns IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.takes_turns || chr(10) END ||\\n\\t    CASE WHEN KQUEST.shareTakeTurns IS NOT NULL THEN 'Parent: ' || KQUEST.shareTakeTurns || chr(10) END\\n    AS \\"Takes Turns\\",\\n\\t    CASE WHEN REPCARDFALL.play_part IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.play_part IS NOT NULL THEN REPCARDFALL.play_part END ||\\n\\t    \\tCASE WHEN REPCARDFALL.play_part_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.play_part IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.play_part IS NOT NULL THEN REPCARDWINTER.play_part END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.play_part_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.play_part IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.play_part IS NOT NULL THEN REPCARDSPRING.play_part END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.play_part_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN KSNAPSHOT.participates IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.participates || chr(10) END ||\\n\\t    CASE WHEN KQUEST.playWell IS NOT NULL THEN 'Parent: ' || KQUEST.playWell || chr(10) END\\n    AS \\"Participates in Play\\",\\n\\t    CASE WHEN REPCARDFALL.follows_direction IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.follows_direction IS NOT NULL THEN REPCARDFALL.follows_direction END ||\\n\\t    \\tCASE WHEN REPCARDFALL.follows_direction_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.follows_direction IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.follows_direction IS NOT NULL THEN REPCARDWINTER.follows_direction END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.follows_direction_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.follows_direction IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.follows_direction IS NOT NULL THEN REPCARDSPRING.follows_direction END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.follows_direction_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Follows Directions\\",\\n    \\tCASE WHEN KSNAPSHOT.transition IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.transition || chr(10) END\\n    AS \\"Transitions Between Activities\\",\\n    \\tCASE WHEN KSNAPSHOT.sel IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.sel || chr(10) || CASE WHEN KSNAPSHOT.sel = 'Yes' THEN KSNAPSHOT.selnote END END\\n    AS \\"Social Emotional / Behavioral Support\\",\\n    \\tCASE WHEN REPCARDFALL.social_comment IS NOT NULL THEN 'RC Fall: ' || REPCARDFALL.social_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDWINTER.social_comment IS NOT NULL THEN 'RC Winter: ' || REPCARDWINTER.social_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDSPRING.social_comment IS NOT NULL THEN 'RC Spring: ' || REPCARDSPRING.social_comment || chr(10) END\\n    AS \\"Social Skills Comment\\",\\n    \\n    -- Self Help\\n    \\n\\t    CASE WHEN REPCARDFALL.remove_coat IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.remove_coat IS NOT NULL THEN REPCARDFALL.remove_coat END ||\\n\\t    \\tCASE WHEN REPCARDFALL.remove_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.remove_coat IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.remove_coat IS NOT NULL THEN REPCARDWINTER.remove_coat END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.remove_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.remove_coat IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.remove_coat IS NOT NULL THEN REPCARDSPRING.remove_coat END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.remove_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Removes Coat\\",\\n\\t    CASE WHEN REPCARDFALL.puts_coat IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.puts_coat IS NOT NULL THEN REPCARDFALL.puts_coat END ||\\n\\t    \\tCASE WHEN REPCARDFALL.puts_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.puts_coat IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.puts_coat IS NOT NULL THEN REPCARDWINTER.puts_coat END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.puts_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.puts_coat IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.puts_coat IS NOT NULL THEN REPCARDSPRING.puts_coat END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.puts_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Puts on Coat\\",\\n\\t    CASE WHEN REPCARDFALL.unzip_coat IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.unzip_coat IS NOT NULL THEN REPCARDFALL.unzip_coat END ||\\n\\t    \\tCASE WHEN REPCARDFALL.unzip_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.unzip_coat IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.unzip_coat IS NOT NULL THEN REPCARDWINTER.unzip_coat END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.unzip_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.unzip_coat IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.unzip_coat IS NOT NULL THEN REPCARDSPRING.unzip_coat END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.unzip_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Unzips Coat\\",\\n\\t    CASE WHEN REPCARDFALL.zip_coat IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.zip_coat IS NOT NULL THEN REPCARDFALL.zip_coat END ||\\n\\t    \\tCASE WHEN REPCARDFALL.zip_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.zip_coat IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.zip_coat IS NOT NULL THEN REPCARDWINTER.zip_coat END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.zip_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.zip_coat IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.zip_coat IS NOT NULL THEN REPCARDSPRING.zip_coat END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.zip_coat_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Zips Coat\\",\\n\\t    CASE WHEN REPCARDFALL.ind_bathroom IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.ind_bathroom IS NOT NULL THEN REPCARDFALL.ind_bathroom END ||\\n\\t    \\tCASE WHEN REPCARDFALL.ind_bathroom_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.ind_bathroom IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.ind_bathroom IS NOT NULL THEN REPCARDWINTER.ind_bathroom END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.ind_bathroom_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.ind_bathroom IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.ind_bathroom IS NOT NULL THEN REPCARDSPRING.ind_bathroom END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.ind_bathroom_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END ||\\n\\t    CASE WHEN KSNAPSHOT.ind_bathroom IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.ind_bathroom || chr(10) END\\n    AS \\"Independent Bathroom Use\\",\\n\\t    CASE WHEN REPCARDFALL.clean_up IS NOT NULL THEN 'RC Fall: ' || \\n\\t    \\tCASE WHEN REPCARDFALL.clean_up IS NOT NULL THEN REPCARDFALL.clean_up END ||\\n\\t    \\tCASE WHEN REPCARDFALL.clean_up_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDWINTER.clean_up IS NOT NULL THEN 'RC Winter: ' ||\\n\\t    \\tCASE WHEN REPCARDWINTER.clean_up IS NOT NULL THEN REPCARDWINTER.clean_up END ||\\n\\t    \\tCASE WHEN REPCARDWINTER.clean_up_na = 1 THEN '*' END ||\\n\\t    \\tchr(10) \\n\\t    END ||\\n\\t    CASE WHEN REPCARDSPRING.clean_up IS NOT NULL THEN 'RC Spring: ' ||\\n\\t    \\tCASE WHEN REPCARDSPRING.clean_up IS NOT NULL THEN REPCARDSPRING.clean_up END ||\\n\\t    \\tCASE WHEN REPCARDSPRING.clean_up_na = 1 THEN '*' END ||\\n\\t    \\tchr(10)\\n\\t    END \\n    AS \\"Clean Up Classroom\\",\\n    \\tCASE WHEN KSNAPSHOT.snack IS NOT NULL THEN 'MPC: ' || KSNAPSHOT.snack || chr(10) END\\n    AS \\"Open Snack\\",\\n    \\tCASE WHEN REPCARDFALL.help_comment IS NOT NULL THEN 'RC Fall: ' || REPCARDFALL.help_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDWINTER.help_comment IS NOT NULL THEN 'RC Winter: ' || REPCARDWINTER.help_comment || chr(10) END ||\\n    \\tCASE WHEN REPCARDSPRING.help_comment IS NOT NULL THEN 'RC Spring: ' || REPCARDSPRING.help_comment || chr(10) END\\n    AS \\"Self Help Comment\\"\\nFROM \\n\\tstudents\\n\\tINNER JOIN ~[temp.table.current.selection:students] stusel ON stusel.dcid = students.dcid\\n\\tLEFT JOIN REPCARD REPCARDFALL ON students.dcid = REPCARDFALL.studentsdcid and REPCARDFALL.season = 'Fall'\\n\\tLEFT JOIN REPCARD REPCARDWINTER ON students.dcid = REPCARDWINTER.studentsdcid and REPCARDWINTER.season = 'Winter'\\n\\tLEFT JOIN REPCARD REPCARDSPRING ON students.dcid = REPCARDSPRING.studentsdcid and REPCARDSPRING.season = 'Spring'\\n\\tLEFT JOIN KQUEST ON students.dcid = KQUEST.studentsdcid\\n\\tLEFT JOIN KSNAPSHOT ON students.dcid = KSNAPSHOT.studentsdcid\\nWHERE \\n\\tstudents.enroll_status = 0\\n    AND ~(curschoolid) IN (0, students.schoolid)\\nORDER BY \\n\\tstudents.lastfirst\\n\\t", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}]}	f	3	2026-02-13 14:35:09.134095	2026-02-13 16:21:11.120719
