attrs": {"textAlign": null}, "content": [{"text": "[ ] Downloads completing to correct folders", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] *arr suite scanning and matching libraries", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] IPTV channels loading in Dispatcharr", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] Homepage dashboard showing all services green", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] Test after Mac Mini reboot (everything comes back up?)", "type": "text"}]}]}]}, {"type": "heading", "attrs": {"level": 3, "textAlign": null}, "content": [{"text": "Cleanup", "type": "text"}]}, {"type": "bulletList", "attrs": {"tight": true}, "content": [{"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] Remove SMB auto-mount config for Blade", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] Update Homepage widgets to point at local drive", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] Shut down Docker services on Blade", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] Update Cloudflare DDNS to remove ", "type": "text"}, {"text": ".blade", "type": "text", "marks": [{"type": "code"}]}, {"text": " subdomains", "type": "text"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "[ ] Decide fate of old 24TB ext4 drive", "type": "text"}]}]}, {"type": "listItem", "