20	VPS Information	{"type": "doc", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "ssh root@107.174.67.189", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Hello David Plaskett,", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Thank you for your KVM VPS order with RackNerd! In this email you will find the login details so that you can begin utilizing your service with us. This email will contain your KVM VPS root info, as well as SolusVM credentials (NerdVM control panel).", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "If you have just placed your order, please allow up to 10 minutes for your server to be installed before attempting to use it.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Server Details", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "=============================", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "4 GB KVM VPS (New Year Special) (Server Label: racknerd-843ffa6)", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "IP Address: 107.174.67.189", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Username: root", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Root Password: Hrh1Poz88ygBWJ539V", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "SSH Port 22", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "You can access your VPS using any SSH program such as PuTTY. Watch this tutorial to learn how.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": ">> SolusVM Control Panel Access (NerdVM) <<", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "=============================", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "SolusVM Credentials are as follows. Please use SolusVM if you need to restart, console or re-install your VPS.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "URL: ", "type": "text"}, {"text": "https://nerdvm.racknerd.com/", "type": "text", "marks": [{"type": "link", "attrs": {"rel": "noopener noreferrer nofollow", "href": "https://nerdvm.racknerd.com/", "class": null, "title": null, "target": "_blank"}}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Username: vmuser303116", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Password: 47ymk0K3fIrUTGj (If you already have access to the above control panel please use your existing password)", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Helpful Resources & Tutorials", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "=============================", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "We want to make sure you have the information you need to get started with your VPS. Below are some resources and guides that will help you set things up smoothly:", "type": "text"}]}, {"type": "orderedList", "attrs": {"type": null, "start": 1, "tight": false}, "content": [{"type": "listItem", "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "How to SSH into Your VPS", "type": "text", "marks": [{"type": "bold"}]}, {"type": "hardBreak"}, {"text": 